{
    "type": "object",
    "title": "Chat Completions Request",
    "description": "OpenAI-compatible chat completions API request format",
    "required": [
        "model",
        "messages"
    ],
    "properties": {
        "model": {
            "type": "string",
            "description": "Model name to use for the request",
            "enum": ["z-ai/glm-5"]
        },
        "messages": {
            "type": "array",
            "description": "Array of conversation messages with roles",
            "minItems": 1,
            "items": {
                "type": "object",
                "required": [
                    "role",
                    "content"
                ],
                "properties": {
                    "role": {
                        "type": "string",
                        "enum": [
                            "system",
                            "user",
                            "assistant"
                        ],
                        "description": "Message role"
                    },
                    "content": {
                        "type": "string",
                        "description": "Message content"
                    }
                }
            }
        },
        "stream": {
            "type": "boolean",
            "description": "Enable streaming response",
            "default": false
        },
        "max_tokens": {
            "type": "integer",
            "minimum": 1,
            "maximum": 131072,
            "description": "Maximum number of tokens to generate",
            "default": 131072
        },
        "temperature": {
            "type": "number",
            "minimum": 0,
            "maximum": 2,
            "description": "Controls randomness in output (higher = more random)",
            "default": 1
        },
        "top_p": {
            "type": "number",
            "minimum": 0,
            "maximum": 1,
            "description": "Nucleus sampling parameter (controls diversity)",
            "default": 1
        },
        "presence_penalty": {
            "type": "number",
            "minimum": -2,
            "maximum": 2,
            "description": "Penalty for new topics",
            "default": 0
        },
        "frequency_penalty": {
            "type": "number",
            "minimum": -2,
            "maximum": 2,
            "description": "Penalty for frequent tokens",
            "default": 0
        }
    }
}

